   235	mp::MemorySize mp::DefaultVMImageVault::minimum_image_size_for(const std::string& id)
   236	{
   237	    auto prepared_image_entry = prepared_image_records.find(id);
   238	    if (prepared_image_entry != prepared_image_records.end())
   239	    {
   240	        const auto& record = prepared_image_entry->second;
   241	
   242	        return get_image_size(record.image.image_path);
   243	    }
   244	
   245	    for (const auto& instance_image_entry : instance_image_records)
   246	    {
   247	        const auto& record = instance_image_entry.second;
   248	
   249	        if (record.image.id == id)
   250	        {
   251	            return get_image_size(record.image.image_path);
   252	        }
   253	    }
   254	
   255	    throw std::runtime_error(fmt::format("Cannot determine minimum image size for id \'{}\'", id));
   256	}
   257	void mp::DefaultVMImageVault::clone(const std::string& source_instance_name,
   258	                                    const std::string& destination_instance_name)
   259	{
   260	    const auto source_iter = instance_image_records.find(source_instance_name);
   261	
   262	    if (source_iter == instance_image_records.end())
   263	    {
   264	        throw std::runtime_error(source_instance_name + " does not exist in the image records");
   265	    }
   266	
   267	    if (instance_image_records.find(destination_instance_name) != instance_image_records.end())
   268	    {
   269	        throw std::runtime_error(destination_instance_name +
   270	                                 " already exists in the image records");
   271	    }
   272	
   273	    auto& dest_vault_record = instance_image_records[destination_instance_name] =
   274	        instance_image_records[source_instance_name];
   275	
   276	    // string replacement is "instances/<src_name>"->"instances/<dest_name>" instead of
   277	    // "<src_name>"->"<dest_name>", because the second one might match other substrings of the
   278	    // metadata.
   279	    auto image_path = dest_vault_record.image.image_path.string();
   280	    boost::replace_all(image_path,
   281	                       "instances/" + source_instance_name,
   282	                       "instances/" + destination_instance_name);
   283	    dest_vault_record.image.image_path = image_path;
   284	
   285	    persist_instance_records();
   286	}
   287	
   288	mp::VMImage mp::DefaultVMImageVault::download_and_prepare_source_image(
   289	    const VMImageInfo& info,
   290	    std::optional<VMImage>& existing_source_image,
   291	    const QDir& image_dir,
   292	    const FetchType& fetch_type,
   293	    const PrepareAction& prepare,
   294	    const ProgressMonitor& monitor)
   295	{
   296	    VMImage source_image;
   297	    auto id = info.id;
   298	
   299	    if (existing_source_image)
   300	    {
   301	        source_image = *existing_source_image;
   302	    }
   303	    else
   304	    {
   305	        QFileInfo file_info{info.image_location};
   306	
   307	        source_image.id = id.toStdString();
   308	        source_image.image_path = image_dir.filePath(file_info.fileName()).toStdString();
   309	        source_image.original_release = info.release_title.toStdString();
   310	        source_image.release_date = info.version.toStdString();
   311	        source_image.os = info.os.toStdString();
   312	
   313	        for (const auto& alias : info.aliases)
   314	        {
   315	            source_image.aliases.push_back(alias.toStdString());
   316	        }
   317	    }
   318	
   319	    mp::vault::DeleteOnException image_file{source_image.image_path};
   320	
   321	    try
   322	    {
   323	        url_downloader->download_to(info.image_location,
   324	                                    MP_PLATFORM.path_to_qstr(source_image.image_path),
   325	                                    info.size,
   326	                                    LaunchProgress::IMAGE,
   327	                                    monitor);
   328	
   329	        if (info.verify)
   330	        {
   331	            mpl::debug(category, "Verifying hash \"{}\"", id);
   332	            monitor(LaunchProgress::VERIFY, -1);
   333	            MP_IMAGE_VAULT_UTILS.verify_file_hash(source_image.image_path, id.toStdString());
   334	        }
   335	
   336	        if (source_image.image_path.extension() == ".xz")
   337	        {
   338	            source_image.image_path =
   339	                MP_IMAGE_VAULT_UTILS.extract_file(source_image.image_path, monitor, true);
   340	        }
   341	
   342	        auto prepared_image = prepare(source_image);
   343	        remove_source_images(source_image, prepared_image);
   344	
   345	        return prepared_image;
   346	    }
   347	    catch (const AbortedDownloadException&)
   348	    {
   349	        throw;
   350	    }
   351	    catch (const std::exception& e)
   352	    {
   353	        throw CreateImageException(e.what());
   354	    }
   355	}
