   357	std::filesystem::path mp::DefaultVMImageVault::extract_image_from(
   358	    const VMImage& source_image,
   359	    const ProgressMonitor& monitor,
   360	    const std::filesystem::path& dest_dir)
   361	{
   362	    MP_UTILS.make_dir(dest_dir);
   363	    QFileInfo file_info{source_image.image_path};
   364	    const auto image_name = file_info.fileName().remove(".xz");
   365	    const auto image_path = QDir(dest_dir).filePath(image_name);
   366	
   367	    return MP_IMAGE_VAULT_UTILS.extract_file(MP_PLATFORM.qstr_to_path(image_path), monitor);
   368	}
