   396	mp::VMImage mp::DefaultVMImageVault::finalize_image_records(const Query& query,
   397	                                                            const VMImage& prepared_image,
   398	                                                            const std::string& id,
   399	                                                            const mp::Path& dest_dir)
   400	{
   401	    VMImage vm_image;
   402	
   403	    if (!query.name.empty())
   404	    {
   405	        vm_image = image_instance_from(prepared_image, dest_dir);
   406	        instance_image_records[query.name] = {vm_image, query, std::chrono::system_clock::now()};
   407	    }
   408	
   409	    // Do not save the instance name for prepared images
   410	    Query prepared_query{query};
   411	    prepared_query.name = "";
   412	    prepared_image_records[id] = {prepared_image, prepared_query, std::chrono::system_clock::now()};
   413	
   414	    persist_instance_records();
   415	    persist_image_records();
   416	
   417	    return vm_image;
   418	}
