   430	void mp::DefaultVMImageVault::amend_db()
   431	{
   432	    for (auto& instance_image_entry : prepared_image_records)
   433	    {
   434	        auto& record = instance_image_entry.second;
   435	
   436	        if (record.image.os.empty())
   437	        {
   438	            record.image.os = "Ubuntu";
   439	        }
   440	    }
   441	
   442	    for (auto& instance_image_entry : instance_image_records)
   443	    {
   444	        auto& record = instance_image_entry.second;
   445	
   446	        if (record.query.query_type == Query::Type::Alias && record.image.os.empty())
   447	        {
   448	            record.image.os = "Ubuntu";
   449	        }
   450	    }
